import{_ as a,o as r,c as t,a2 as o}from"./chunks/framework.Bix3-HpO.js";const u=JSON.parse('{"title":"Creating Broker Review Pages","description":"Creating Broker Review Pages with FXT Theme","frontmatter":{"title":"Creating Broker Review Pages","description":"Creating Broker Review Pages with FXT Theme","weight":40,"extra":{"order":40},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/fxt/creating-broker-pages"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/fxt/creating-broker-pages"}],["meta",{"property":"og:title","content":"Creating Broker Review Pages"}],["meta",{"property":"og:description","content":"Creating Broker Review Pages with FXT Theme"}],["meta",{"name":"twitter:title","content":"Creating Broker Review Pages"}],["meta",{"name":"twitter:description","content":"Creating Broker Review Pages with FXT Theme"}]]},"headers":[],"relativePath":"docs/fxt/creating-broker-pages.md","filePath":"docs/fxt/creating-broker-pages.md"}'),i={name:"docs/fxt/creating-broker-pages.md"};function s(n,e,l,g,d,c){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="creating-broker-review-pages" tabindex="-1">Creating Broker Review Pages <a class="header-anchor" href="#creating-broker-review-pages" aria-label="Permalink to &quot;Creating Broker Review Pages&quot;">​</a></h1><p>In your WordPress dashboard you will find a new menu item called <strong>Brokers</strong> right below the <strong>Pages</strong> menu link. Click <code>Add New</code> to add a new broker review.</p><hr><h2 id="broker-page-templates" tabindex="-1">Broker Page Templates <a class="header-anchor" href="#broker-page-templates" aria-label="Permalink to &quot;Broker Page Templates&quot;">​</a></h2><p>This page describes broker-specific fields. For broker page templates, please follow this <a href="/docs/fxt/broker-page-templates">link</a>.</p><hr><h2 id="broker-fields" tabindex="-1">Broker Fields <a class="header-anchor" href="#broker-fields" aria-label="Permalink to &quot;Broker Fields&quot;">​</a></h2><p>Besides adding the broker title and content as usual, you&#39;ll find <strong>Broker Fields</strong> section below the page content. Here you can define comprehensive properties for each broker. These fields are organized in separate tabs and have descriptions to make it easy for you to fill them in. These properties are used throughout the website, so please make sure to complete them.</p><hr><h2 id="basic-information-tab" tabindex="-1">Basic Information Tab <a class="header-anchor" href="#basic-information-tab" aria-label="Permalink to &quot;Basic Information Tab&quot;">​</a></h2><h3 id="core-details" tabindex="-1">Core Details <a class="header-anchor" href="#core-details" aria-label="Permalink to &quot;Core Details&quot;">​</a></h3><ul><li><strong>Logo</strong>: Upload the broker&#39;s logo (150x150 pixels)</li><li><strong>Name</strong>: The official name of the broker</li><li><strong>Type</strong>: Select broker type (CFD, ECN, STP, Market Maker, etc.)</li><li><strong>Website URL</strong>: The official website of the broker</li><li><strong>Tagline/Main Feature</strong>: A short phrase describing the broker&#39;s main selling point</li></ul><h3 id="company-information" tabindex="-1">Company Information <a class="header-anchor" href="#company-information" aria-label="Permalink to &quot;Company Information&quot;">​</a></h3><ul><li><strong>Year Founded</strong>: The year the broker was established</li><li><strong>Headquarters Location</strong>: The location of the broker&#39;s main office</li><li><strong>Regulations</strong>: Select regulatory bodies that oversee the broker</li><li><strong>Licenses</strong>: Enter the broker&#39;s license numbers and details</li></ul><h3 id="geographic-coverage" tabindex="-1">Geographic Coverage <a class="header-anchor" href="#geographic-coverage" aria-label="Permalink to &quot;Geographic Coverage&quot;">​</a></h3><ul><li><strong>Supported Countries</strong>: Select countries where the broker&#39;s services are available</li><li><strong>Restricted Countries</strong>: Select countries where the broker does not operate</li></ul><ul><li>You need to fill in just one of the fields, either one will do.</li></ul><hr><h2 id="account-links-tab" tabindex="-1">Account Links Tab <a class="header-anchor" href="#account-links-tab" aria-label="Permalink to &quot;Account Links Tab&quot;">​</a></h2><ul><li><strong>Trading Account Link</strong>: Direct link to open a real trading account</li><li><strong>Demo Account Link</strong>: Direct link to open a demo account</li></ul><hr><h2 id="ratings-tab" tabindex="-1">Ratings Tab <a class="header-anchor" href="#ratings-tab" aria-label="Permalink to &quot;Ratings Tab&quot;">​</a></h2><ul><li><strong>Overall Rating</strong>: The main score for the broker (used in all comparisons and listings)</li><li><strong>Rating #1 - #6</strong>: Six additional rating fields for specific aspects (e.g., &quot;Customer Support&quot;, &quot;Platform Stability&quot;, &quot;Trading Conditions&quot;, etc.)</li></ul><p>The labels for these ratings can be customized in the <strong>Theme Options</strong> -&gt; <strong>Strings</strong>.</p><hr><h2 id="terms-tab" tabindex="-1">Terms Tab <a class="header-anchor" href="#terms-tab" aria-label="Permalink to &quot;Terms Tab&quot;">​</a></h2><ul><li><strong>Terms</strong>: Any specific terms and conditions associated with the broker</li></ul><hr><h2 id="trading-conditions-tab" tabindex="-1">Trading Conditions Tab <a class="header-anchor" href="#trading-conditions-tab" aria-label="Permalink to &quot;Trading Conditions Tab&quot;">​</a></h2><ul><li><strong>Min Trade Size</strong>: The smallest trade size allowed</li><li><strong>Average Spread EURUSD</strong>: The average spread for the EUR/USD pair</li><li><strong>Max Leverage</strong>: The maximum leverage offered</li></ul><hr><h2 id="trading-instruments-tab" tabindex="-1">Trading Instruments Tab <a class="header-anchor" href="#trading-instruments-tab" aria-label="Permalink to &quot;Trading Instruments Tab&quot;">​</a></h2><h3 id="instrument-summary" tabindex="-1">Instrument Summary <a class="header-anchor" href="#instrument-summary" aria-label="Permalink to &quot;Instrument Summary&quot;">​</a></h3><ul><li><strong>Instruments</strong>: A summary description of available instruments</li></ul><h3 id="pair-types" tabindex="-1">Pair Types <a class="header-anchor" href="#pair-types" aria-label="Permalink to &quot;Pair Types&quot;">​</a></h3><ul><li><strong>Pair Types</strong>: Select the types of currency pairs offered (Major, Minor, Exotic)</li></ul><h3 id="instrument-counts" tabindex="-1">Instrument Counts <a class="header-anchor" href="#instrument-counts" aria-label="Permalink to &quot;Instrument Counts&quot;">​</a></h3><ul><li><strong>Currency Pairs</strong>: Number of available currency pairs</li><li><strong>Cryptocurrencies</strong>: Number of available cryptocurrencies</li><li><strong>Metals</strong>: Number of available metals</li><li><strong>Stocks/Equities</strong>: Number of available stocks</li><li><strong>Indices</strong>: Number of available indices</li><li><strong>Energy</strong>: Number of available energy products</li><li><strong>Commodities</strong>: Number of available commodities</li><li><strong>Bonds</strong>: Number of available bonds</li><li><strong>ETFs</strong>: Number of available ETFs</li><li><strong>Options/Futures</strong>: Number of available options or futures</li></ul><hr><h2 id="trading-platforms-tab" tabindex="-1">Trading Platforms Tab <a class="header-anchor" href="#trading-platforms-tab" aria-label="Permalink to &quot;Trading Platforms Tab&quot;">​</a></h2><ul><li><strong>Trading Platforms</strong>: Select supported platforms (MetaTrader 4, MetaTrader 5, cTrader, etc.)</li><li><strong>Mobile Trading</strong>: Enable/disable mobile trading availability</li></ul><hr><h2 id="payment-options-tab" tabindex="-1">Payment Options Tab <a class="header-anchor" href="#payment-options-tab" aria-label="Permalink to &quot;Payment Options Tab&quot;">​</a></h2><h3 id="payment-methods" tabindex="-1">Payment Methods <a class="header-anchor" href="#payment-methods" aria-label="Permalink to &quot;Payment Methods&quot;">​</a></h3><ul><li><strong>Deposit Methods</strong>: Select supported deposit methods</li><li><strong>Withdrawal Methods</strong>: Select supported withdrawal methods</li><li><strong>Min. Deposit</strong>: The minimum deposit amount</li><li><strong>Withdrawal Processing Time</strong>: Typical time for withdrawal processing</li><li><strong>Deposit Fees</strong>: Information about deposit fees</li><li><strong>Withdrawal Fees</strong>: Information about withdrawal fees</li></ul><hr><h2 id="customer-support-tab" tabindex="-1">Customer Support Tab <a class="header-anchor" href="#customer-support-tab" aria-label="Permalink to &quot;Customer Support Tab&quot;">​</a></h2><ul><li><strong>Support Channels</strong>: Describe available support channels (chat, email, phone, etc.)</li><li><strong>Support Languages</strong>: Select languages supported by customer service</li><li><strong>Availability</strong> and <strong>Average response time</strong></li></ul><hr><h2 id="education-tab" tabindex="-1">Education Tab <a class="header-anchor" href="#education-tab" aria-label="Permalink to &quot;Education Tab&quot;">​</a></h2><p>Several true or false fields:</p><ul><li><strong>Learning materials</strong></li><li><strong>Market analysis/research</strong></li><li><strong>Economic calendar</strong></li><li><strong>Trading signals</strong></li></ul><hr><h2 id="additional-features-tab" tabindex="-1">Additional Features Tab <a class="header-anchor" href="#additional-features-tab" aria-label="Permalink to &quot;Additional Features Tab&quot;">​</a></h2><p>True or false fields for additional features such as:</p><ul><li><strong>Negative balance protection</strong></li><li><strong>PAMM/MAM accounts</strong></li><li><strong>Social/copy trading</strong></li><li>etc.</li></ul><hr><h2 id="broker-page-blocks" tabindex="-1">Broker Page Blocks <a class="header-anchor" href="#broker-page-blocks" aria-label="Permalink to &quot;Broker Page Blocks&quot;">​</a></h2><p>To present the information more visually, you can use <a href="/docs/fxt/broker-page-blocks">broker blocks</a> in broker page contents, as well as generic blocks such as FAQs, Recent posts, etc.</p><hr><h2 id="broker-categories-and-tags" tabindex="-1">Broker Categories and Tags <a class="header-anchor" href="#broker-categories-and-tags" aria-label="Permalink to &quot;Broker Categories and Tags&quot;">​</a></h2><p>You can assign broker categories and tags to brokers. You do that the same way you&#39;d do it for regular posts. You can also manage your broker categories and broker tags by visiting their corresponding pages under the &quot;Brokers&quot; menu item.</p><hr><h2 id="review-snippet" tabindex="-1">Review Snippet <a class="header-anchor" href="#review-snippet" aria-label="Permalink to &quot;Review Snippet&quot;">​</a></h2><p>For all your broker review pages, FXT generates <strong>Review Snippet Structured Data</strong> (schema.org) markup. The rating value used is the &quot;Overall Rating&quot; field from the Ratings tab. It is generated automatically, so you don&#39;t need to do anything; however, you can turn it off if desired. You can test your pages <a href="https://search.google.com/structured-data/testing-tool" target="_blank" rel="noreferrer">here</a>.</p><hr><h2 id="next-step" tabindex="-1">Next Step <a class="header-anchor" href="#next-step" aria-label="Permalink to &quot;Next Step&quot;">​</a></h2><p><a href="/docs/fxt/broker-page-templates">Page Templates</a></p>',68)])])}const b=a(i,[["render",s]]);export{u as __pageData,b as default};
